  ('heelevel3-d0d1b9a2-moex-00584', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-f6c431ec', 'sub-heelevel3-d0d1b9a2-04', NULL, 'single_choice', '布坎南（J.M.Buchanan）所稱「財政剩餘」（fiscalresiduum）是指：', '["居民消費轄區地方公共財的利益扣除其租稅負擔", "地方政府主動降低租稅收入或增加支出，以刺激經濟活動，促使社會利益提高", "納稅人低估公共財的成本，極力爭取政府擴大公共支出", "地方政府歲入與歲出之差額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:03+00:00", "source_pdf_sha1": "13fea319c49b", "answer_pdf_sha1": "816865504eb7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
